SELECT m.message_type AS type, m.message_status AS isRead, m.message_title AS title, m.message_content AS content, m.doc_folder AS url, m.doc_parent_id AS lastFolderId, m.inform_time AS time, m.message_id AS id, m.doc_house_id AS documentHouseId, hu.house_id, bu.doc_id FROM doc_bs_message m LEFT JOIN doc_bs_document d ON m.doc_parent_id = d.bus_id LEFT JOIN (SELECT DISTINCT house_id FROM doc_sys_house_user WHERE is_deleted = 0 AND rel_id IN
#{item}
) hu ON hu.house_id = d.house_id LEFT JOIN (SELECT DISTINCT doc_id FROM doc_bs_document_user WHERE is_deleted = 0 AND rel_id IN
#{item}
) bu ON bu.doc_id = d.bus_id WHERE m.user_id = #{userId} AND TRUNC(SYSDATE) - 30 <= TRUNC(m.create_time) ORDER BY m.create_time DESC
